class Solution {
    public java.util.List<java.util.List<Integer>> combinationSum(int[] candidates, int target) {
        java.util.List<java.util.List<Integer>> res = new java.util.ArrayList<>();
        java.util.Arrays.sort(candidates);
        backtrack(candidates, target, 0, new java.util.ArrayList<>(), res);
        return res;
    }
    private void backtrack(int[] cands, int remain, int start, java.util.List<Integer> path, java.util.List<java.util.List<Integer>> res) {
        if (remain == 0) {
            res.add(new java.util.ArrayList<>(path));
            return;
        }
        for (int i = start; i < cands.length; i++) {
            if (cands[i] > remain) break;
            path.add(cands[i]);
            backtrack(cands, remain - cands[i], i, path, res);
            path.remove(path.size() - 1);
        }
    }
}

