class Solution {
    public boolean exist(char[][] board, String word) {
        for (int r = 0; r < board.length; r++)
            for (int c = 0; c < board[0].length; c++)
                if (dfs(board, word, 0, r, c)) return true;
        return false;
    }
    private boolean dfs(char[][] board, String word, int i, int r, int c) {
        if (i == word.length()) return true;
        if (r < 0 || c < 0 || r >= board.length || c >= board[0].length || board[r][c] != word.charAt(i)) return false;
        char tmp = board[r][c];
        board[r][c] = '#';
        boolean found = dfs(board, word, i + 1, r + 1, c) || dfs(board, word, i + 1, r - 1, c)
            || dfs(board, word, i + 1, r, c + 1) || dfs(board, word, i + 1, r, c - 1);
        board[r][c] = tmp;
        return found;
    }
}

