    def totalNQueens(self, n: int) -> int:
        cols = [False] * n
        diag1 = [False] * (2 * n)
        diag2 = [False] * (2 * n)

        def backtrack(row: int) -> int:
            if row == n:
                return 1
            count = 0
            for c in range(n):
                d1 = row - c + n
                d2 = row + c
                if cols[c] or diag1[d1] or diag2[d2]:
                    continue
                cols[c] = diag1[d1] = diag2[d2] = True
                count += backtrack(row + 1)
                cols[c] = diag1[d1] = diag2[d2] = False
            return count

        return backtrack(0)

