class Solution {
    public java.util.List<java.util.List<String>> solveNQueens(int n) {
        java.util.List<java.util.List<String>> res = new java.util.ArrayList<>();
        char[][] board = new char[n][n];
        for (char[] row : board) java.util.Arrays.fill(row, '.');
        backtrack(n, 0, new boolean[n], new boolean[2 * n], new boolean[2 * n], board, res);
        return res;
    }
    private void backtrack(int n, int row, boolean[] cols, boolean[] diag1, boolean[] diag2, char[][] board, java.util.List<java.util.List<String>> res) {
        if (row == n) {
            java.util.List<String> conf = new java.util.ArrayList<>();
            for (char[] r : board) conf.add(new String(r));
            res.add(conf);
            return;
        }
        for (int c = 0; c < n; c++) {
            int d1 = row - c + n, d2 = row + c;
            if (cols[c] || diag1[d1] || diag2[d2]) continue;
            cols[c] = diag1[d1] = diag2[d2] = true;
            board[row][c] = 'Q';
            backtrack(n, row + 1, cols, diag1, diag2, board, res);
            board[row][c] = '.';
            cols[c] = diag1[d1] = diag2[d2] = false;
        }
    }
}

