class Solution {
    public java.util.List<java.util.List<String>> partition(String s) {
        java.util.List<java.util.List<String>> res = new java.util.ArrayList<>();
        backtrack(s, 0, new java.util.ArrayList<>(), res);
        return res;
    }
    private void backtrack(String s, int start, java.util.List<String> path, java.util.List<java.util.List<String>> res) {
        if (start == s.length()) {
            res.add(new java.util.ArrayList<>(path));
            return;
        }
        for (int end = start; end < s.length(); end++) {
            if (isPalindrome(s, start, end)) {
                path.add(s.substring(start, end + 1));
                backtrack(s, end + 1, path, res);
                path.remove(path.size() - 1);
            }
        }
    }
    private boolean isPalindrome(String s, int l, int r) {
        while (l < r) if (s.charAt(l++) != s.charAt(r--)) return false;
        return true;
    }
}

